sp_angular_provider.script:
function mandatoryValidator() {

    this.validate = function(form) {

        if (!form || !form._fields) return true;

        var missingFields = [];

        angular.forEach(form._fields, function(fieldObj) {

            if (fieldObj.mandatory && fieldObj.visible) {

                var value = fieldObj.value;

                if (!value || value === "" || value === "-1") {
                    missingFields.push(fieldObj.label);
                }
            }
        });

        if (missingFields.length > 0) {
            return {
                valid: false,
                message: "Please fill mandatory fields: " + missingFields.join(", ")
            };
        }

        return { valid: true };
    };
}
